const contextPacket = $json.execution_context_packet || { payload: { target_platform: 'generic' } };
const platform = contextPacket.payload?.target_platform || 'generic';
const platformFormats = {
  youtube: { metadata_fields: ['title', 'description', 'tags', 'chapters', 'thumbnail_description'], required_length: '5-3600_seconds', required_format: 'video_metadata' },
  blog: { metadata_fields: ['title', 'excerpt', 'tags', 'category', 'featured_image_description'], required_format: 'markdown' },
  podcast: { metadata_fields: ['episode_title', 'episode_description', 'show_notes', 'guest_names', 'duration'], required_format: 'audio_metadata' },
  email: { metadata_fields: ['subject_line', 'preview_text', 'call_to_action', 'unsubscribe_link'], required_format: 'html_friendly' },
  generic: { metadata_fields: ['title', 'description'], required_format: 'generic' }
};
const platformConfig = platformFormats[platform] || platformFormats.generic;
const packagedOutput = {
  platform,
  metadata: { title: $json.final_script_packet?.payload?.title || 'Untitled', description: $json.final_script_packet?.payload?.summary || 'Content summary' },
  format_applied: platformConfig.required_format,
  metadata_fields: platformConfig.metadata_fields
};
return [{ json: { ...$json, platform_package: packagedOutput, platform_packaging_complete: true } }];

const packet = {
  instance_id: 'PKG-' + Date.now(),
  artifact_family: 'platform_package_packet',
  schema_version: '1.0.0',
  producer_workflow: 'CWF-320',
  dossier_ref: $json.dossier_id || 'DOSSIER-UNSPECIFIED',
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    platform_packaging_complete: true,
    platform: $json.platform_package.platform,
    metadata: $json.platform_package.metadata,
    format_applied: $json.platform_package.format_applied,
    metadata_fields_populated: $json.platform_package.metadata_fields.length
  }
};
return [{ json: { ...$json, platform_package_packet: packet, packet_emitted: true } }];

try {
  const SkillLoader = require('../../../engine/skill_loader/skill_loader.js');
  const loader = new SkillLoader();

  if (!loader.skills_registry || Object.keys(loader.skills_registry).length === 0) {
    const initResult = await loader.initialize();
    if (initResult.status !== 'initialized') {
      throw new Error('Failed to initialize SkillLoader');
    }
  }

  const workflowId = 'CWF-320';
  const defaultSkillMap = {"CWF-310":"M-001","CWF-320":"M-001","CWF-330":"M-001","CWF-340":"M-001","CWF-410":"M-001","CWF-420":"M-001","CWF-430":"M-001","CWF-440":"M-001","CWF-510":"M-001","CWF-520":"M-001","CWF-530":"M-001"};
  const skillId = $json.skill_id || defaultSkillMap[workflowId] || 'M-001';
  const dossierId = $json.dossier_context?.dossier_id || $json.dossier_id || 'DOSSIER-UNSPECIFIED';

  const contextPacket = {
    dossier_id: dossierId,
    workflow_id: workflowId,
    ...(typeof $json.user_context === 'object' ? $json.user_context : {}),
    ...(typeof $json.route_context === 'object' ? $json.route_context : {})
  };

  const dossierState = typeof $json.dossier === 'object' ? $json.dossier : {};
  const result = await loader.executeSkill(skillId, contextPacket, dossierState);

  return [{
    json: {
      ...$json,
      phase8_runtime_probe: {
        workflow_id: workflowId,
        skill_id: skillId,
        status: result.status,
        had_error: result.status !== 'SUCCESS',
        error_message: result.status === 'SUCCESS' ? '' : String(result.error || ''),
        timestamp: new Date().toISOString()
      },
      runtime_packet: result.status === 'SUCCESS' ? (result.output || null) : null,
      skill_execution_result: result.status === 'SUCCESS' ? result : null,
      runtime: {
        had_error: result.status !== 'SUCCESS',
        error_message: result.status === 'SUCCESS' ? '' : String(result.error || '')
      }
    }
  }];
} catch (error) {
  const message = String(error && error.message ? error.message : error);
  return [{
    json: {
      ...$json,
      phase8_runtime_probe: {
        workflow_id: 'CWF-320',
        skill_id: null,
        status: 'ERROR',
        had_error: true,
        error_message: message,
        timestamp: new Date().toISOString()
      },
      runtime_packet: null,
      skill_execution_result: null,
      runtime: { had_error: true, error_message: message }
    }
  }];
}
